// コールバック実装群
const coreCallbacks = {
    getOffset: () => Number(offsetInput.value),
    getWindowSec: () => Number(windowSelect.value) / 1000,
    getNoteSpeed: () => noteSpeed,
    getBgmVolume: () => Number(bgmVol.value),
    getAudioDuration: () => player.duration,
    isAudioEnded: () => player.ended,
    isAudioPaused: () => player.paused,
    getAudioTime: () => player.currentTime,
    playAudio: () => player.play(),
    pauseAudio: () => player.pause(),
    setAudioTime: (t) => { player.currentTime = t; },
    setAudioMuted: (m) => { player.muted = m; },
    setAudioVolume: (v) => { player.volume = v; },
    
    updateHUD: (stats) => {
        scoreValEl.textContent = stats.score;
        comboValEl.textContent = stats.combo;
        timeValEl.textContent = Math.max(0, stats.gameTime).toFixed(2);
        accValEl.textContent = stats.accuracy;

        const container = document.getElementById("vocal-portrait-container");
        if (container) {
            // ゲームの種類（優美か勇猛か）を判定する
            // coreがBraveRhythmGameCoreのインスタンス（もしくはクラス名にBraveが含まれる）なら勇猛モード、そうでなければ優美モード
            const isBraveMode = core && (core.constructor.name.includes("Brave") || (core as any).lastHitAttribute !== undefined);
            const attr = isBraveMode ? "brave" : "elegant";

            // コンボ数に応じて回転速度のベースを決定 (コンボが増えるほど倍速になる)
            const speedFactor = 1 + Math.min(stats.combo / 10, 8); // 最高9倍速
            // グローバルスコープの角度を更新
            if (!(window as any)._rainbowAngle) (window as any)._rainbowAngle = 0;
            // 毎フレーム更新するためのアニメーションループをセットアップ (初回のみ)
            if (!(window as any)._rainbowLoopActive) {
                (window as any)._rainbowLoopActive = true;
                const anim = () => {
                    const c = document.getElementById("vocal-portrait-container");
                    if (c) {
                        const currentStatsCombo = Number(comboValEl?.textContent || 0);
                        const sf = 1 + Math.min(currentStatsCombo / 10, 8);
                        (window as any)._rainbowAngle = ((window as any)._rainbowAngle + sf * 1.5) % 360;
                        c.style.setProperty("--rainbow-angle", `${(window as any)._rainbowAngle}deg`);
                    }
                    requestAnimationFrame(anim);
                };
                requestAnimationFrame(anim);
            }
            
            // 優美 (elegant: 青緑 #06b6d4) または 勇猛 (brave: 赤 #ef4444) を強調・広く配置するグラデーションを定義
            // 属性カラーが全体の7割近くを占めるように配分を調整
            let gradientStr = "";
            if (attr === "brave") {
                // 赤 (#ef4444) を強調
                gradientStr = `linear-gradient(#f4ecd8, #f4ecd8), conic-gradient(from var(--rainbow-angle, 0deg), #ef4444 0%, #ef4444 45%, #fbbf24 60%, #a855f7 70%, #06b6d4 80%, #ef4444 95%, #ef4444 100%)`;
            } else {
                // 優美 (elegant, #06b6d4) を強調
                gradientStr = `linear-gradient(#f4ecd8, #f4ecd8), conic-gradient(from var(--rainbow-angle, 0deg), #06b6d4 0%, #06b6d4 45%, #a855f7 60%, #ef4444 70%, #fbbf24 80%, #06b6d4 95%, #06b6d4 100%)`;
            }
            container.style.backgroundImage = gradientStr;

            // コンボが上がると枠の光り（box-shadow）の強さと範囲もダイナミックに増加
            const glowStrength = Math.min(stats.combo, 100);
            const shadowColor = attr === "brave" ? "rgba(239, 68, 68, " : "rgba(6, 182, 212, ";
            container.style.boxShadow = `0 30px 60px rgba(0,0,0,0.36), 0 0 ${10 + glowStrength * 0.4}px ${shadowColor}${0.15 + glowStrength * 0.005})`;

            // --- 案2：スコアに連動した背景「陽炎（ヒートヘイズ）」ゆらぎエフェクトの動的設定 ---
            const stage = document.getElementById("stage");
            if (stage) {
                // スコア最大60,000を基準に盛り上がり度（0.0〜1.0）を算出
                const heatRatio = Math.min(stats.score / 60000, 1.0);
                
                // 初期状態からゆらぎを認識できるよう、ベースライン（初期値）を底上げ
                // ゆらぎ速度 (スコアが高いほど速くなる: 3.0s -> 0.7s)
                const speed = (3.0 - heatRatio * 2.3).toFixed(2) + "s";
                // 歪み傾斜 (初期 0.3deg -> 最大 1.8deg)
                const skew = (0.3 + heatRatio * 1.5).toFixed(2) + "deg";
                // 上下揺れ幅 (初期 1.5px -> 最大 7px)
                const translate = (1.5 + heatRatio * 5.5).toFixed(1) + "px";
                // スケールオフセット (陽炎効果中の僅かな伸縮: 0.004 -> 0.012)
                const scaleOffset = (0.004 + heatRatio * 0.008).toFixed(4);
                // 明るさ (初期から僅かに発光: 1.03 -> 最大 1.25)
                const bright = (1.03 + heatRatio * 0.22).toFixed(2);

                stage.style.setProperty("--haze-speed", speed);
                stage.style.setProperty("--haze-skew", skew);
                stage.style.setProperty("--haze-translate", translate);
                stage.style.setProperty("--haze-scale-offset", scaleOffset);
                stage.style.setProperty("--haze-bright", bright);
            }
        }

        const lanePaths = document.querySelectorAll(".lane-path");
        lanePaths.forEach((lane) => {
            if (stats.combo >= 100) {
                lane.classList.remove("wave-low");
                lane.classList.add("wave-high");
            } else if (stats.combo >= 50) {
                lane.classList.remove("wave-high");
                lane.classList.add("wave-low");
            } else {
                lane.classList.remove("wave-low", "wave-high");
            }
        });
    },
    updateJudgeMeter: (level, color, text, upgradeInfo) => {
        lastJudge.style.color = color;
        meterBars.style.color = color;
        [...meterBars.children].forEach((bar, idx) => {
            bar.classList.toggle("lit", idx < level);
        });
        
        let dispText = text;
        if (upgradeInfo) {
            if (upgradeInfo.isUpgrade) {
                dispText = `${text} (${upgradeInfo.originalText} ➔ 上昇！)`;
                const meterPanel = document.getElementById("judge-meter");
                if (meterPanel) {
                    meterPanel.classList.remove("upgrade-bump");
                    void meterPanel.offsetWidth;
                    meterPanel.classList.add("upgrade-bump");
                }
            } else {
                dispText = `${text} (維持)`;
            }
        }
        lastJudge.textContent = dispText;
    },
    showHitText: (text, color, y) => {
        // 日本語に統一するため判定文字をローカライズ
        const textMap = {
            "パーフェクト": "パーフェクト",
            "グレート": "グレート",
            "グッド": "グッド",
            "ミス": "ミス",
            "PERFECT": "パーフェクト",
            "GREAT": "グレート",
            "GOOD": "グッド",
            "MISS": "ミス",
            "空振り": "空振り",
            "LOCKED!": "ロック！"
        };
        const mappedText = textMap[text] || text;
        const el = document.createElement("div");
        el.className = "hit-text";
        el.textContent = mappedText;
        el.style.color = color;
        el.style.top = `${y}px`;
        laneContainer.appendChild(el);
        setTimeout(() => el.remove(), 560);
    },
    burstAt: (x, y, color, combo) => {
        const ring = document.createElement("div");
        ring.className = "hit-ring";
        ring.style.left = `${x}px`;
        ring.style.top = `${y}px`;
        ring.style.color = color;
        laneContainer.appendChild(ring);
        setTimeout(() => ring.remove(), 380);

        const sparkCount = combo >= 50 ? 16 : 8;
        for (let i = 0; i < sparkCount; i++) {
            const spark = document.createElement("span");
            spark.className = "spark";
            spark.style.left = `${x}px`;
            spark.style.top = `${y}px`;
            spark.style.color = color;
            const angle = Math.PI * 2 * (i / sparkCount) + Math.random() * 0.22;
            const dist = 30 + Math.random() * 74;
            spark.style.setProperty("--tx", `${Math.cos(angle) * dist}px`);
            spark.style.setProperty("--ty", `${Math.sin(angle) * dist}px`);
            laneContainer.appendChild(spark);
            setTimeout(() => spark.remove(), 500);
        }
    },
    showTiming: (diff, windowSec, color) => {
        if (windowSec === 0) {
            timingMarker.style.opacity = 0;
            return;
        }
        const px = Math.max(-80, Math.min(80, (diff / windowSec) * 80));
        timingMarker.style.opacity = 1;
        timingMarker.style.background = color;
        timingMarker.style.boxShadow = `0 0 16px ${color}`;
        timingMarker.style.transform = `translateX(${px}px)`;
        clearTimeout(coreCallbacks.showTiming.timer);
        coreCallbacks.showTiming.timer = setTimeout(() => { timingMarker.style.opacity = 0; }, 520);
    },
    emitVisualizerParticles: (x, y, color, type, char = "", strong = false) => {
        visualizer.emitParticles(x, y, color, type, char, strong);
    },
    triggerCompanionAssist: (strong = false) => {
        companionGroup.forEach((c, idx) => {
            window.setTimeout(() => {
                c.triggerAssist(strong);
                const COMPANION_EFFECTS = {
                    dancer: { chars: "*+~", color: "#f9a8d4" },
                    strings: { chars: "♫♪", color: "#7dd3fc" },
                    mystic: { chars: "*<>*", color: "#5eead4" },
                    salon: { chars: "+*", color: "#fde68a" },
                    clap: { chars: "*", color: "#fef3c7" }
                };
                const def = COMPANION_EFFECTS[c.role] || COMPANION_EFFECTS.clap;
                visualizer.emitParticles(c.pos.x, c.pos.y - 70, def.color, "companion", def.chars[0], strong);
            }, idx * (strong ? 110 : 70));
        });
    },
    adjustAudienceHeat: (delta) => {
        audienceHeat = Math.max(0, Math.min(100, audienceHeat + delta));
        document.getElementById("heat-fill").style.width = `${audienceHeat}%`;
        document.getElementById("heat-value").textContent = `${Math.round(audienceHeat)}%`;
        document.body.dataset.heat = audienceHeat >= 70 ? "high" : audienceHeat >= 35 ? "warm" : "low";

        if (delta > 0) {
            audienceGroup.forEach((a, idx) => {
                window.setTimeout(() => a.cheer(), idx * 55);
            });
        }
    },
    onGameEnd: (results) => {
        core.isPlaying = false;
        core.isPaused = false;
        player.pause();
        playBtn.textContent = "演奏開始";
        
        const total = results.perfects + results.greats + results.goods + results.misses;
        const max = Math.max(1, total * 100);
        const ratio = results.scoreVal / max;
        let rank = "D";
        if (ratio >= 0.95) rank = "S";
        else if (ratio >= 0.82) rank = "A";
        else if (ratio >= 0.66) rank = "B";
        else if (ratio >= 0.48) rank = "C";

        const rankEl = document.getElementById("res-rank");
        rankEl.textContent = rank;
        rankEl.className = `result-rank rank-${rank}`;

        document.getElementById("res-perfect").textContent = results.perfects;
        document.getElementById("res-great").textContent = results.greats;
        document.getElementById("res-good").textContent = results.goods;
        document.getElementById("res-miss").textContent = results.misses;
        document.getElementById("res-maxcombo").textContent = results.maxCombo;
        document.getElementById("res-score").textContent = results.scoreVal;

        resultsModal.classList.add("active");
    },
    onCountdownState: (text, phase) => {
        if (phase === 'active') {
            countdownOverlay.classList.add("active");
            countdownOverlay.classList.remove("approach");
            countdownText.textContent = text;
        } else if (phase === 'approach') {
            countdownOverlay.classList.add("active", "approach");
            countdownText.textContent = text;
        } else {
            countdownOverlay.classList.remove("active", "approach");
            countdownText.textContent = "";
        }
    }
};

// --- メイン初期化処理 ---
async function initExcalibur() {
    const container = document.getElementById("excalibur-canvas-container");
    
    engine = new ex.Engine({
        width: 1920,
        height: 1080,
        backgroundColor: ex.Color.Transparent,
        suppressPlayButton: true,
        displayMode: ex.DisplayMode.Fixed,
        maxFps: 60,
        fixedUpdateFps: 60
    });
    
    container.appendChild(engine.canvas);

    // インスタンス作成
    visualizer = new RhythmVisualizer(
        document.getElementById("visualizer-canvas") as HTMLCanvasElement,
        () => portraitManager ? portraitManager.activeState : "BGM"
    );

    core = new BraveRhythmGameCore(coreCallbacks, (lastAttr) => {
        const hitareas = document.querySelectorAll('.touch-lane-hitarea');
        hitareas.forEach(el => {
            el.classList.remove('locked');
            if (el.dataset.attr === lastAttr) {
                el.classList.add('locked');
            }
        });
    });

    inputManager = new RhythmInputManager(
        (attr, isRelease) => {
            const containerWidth = laneContainer.clientWidth;
            const containerHeight = laneContainer.clientHeight;
            const activeState = portraitManager ? portraitManager.activeState : "BGM";
            core.judgeInput(attr, isRelease, containerWidth, containerHeight, activeState);
            
            const icon = document.querySelector(`.judgment-icon.${attr}`);
            if (icon) {
                if (!isRelease) {
                    icon.classList.add("active");
                } else {
                    icon.classList.remove("active");
                }
            }

            const btn = document.querySelector(`.touch-lane-hitarea.${attr}`);
            if (btn) {
                if (!isRelease) {
                    btn.classList.add("active");
                } else {
                    btn.classList.remove("active");
                }
            }
        },
        () => configModal.classList.contains("active") || pauseModal.classList.contains("active") || resultsModal.classList.contains("active")
    );

    portraitManager = new VocalPortraitManager(
        document.getElementById("vocal-canvas") as HTMLCanvasElement,
        () => core ? core.gameTime : 0,
        () => {
            const track = tracksData[Number(trackSelect.value)];
            const fileName = track ? getTrackFile(track) : "";
            return track?.bpms?.[fileName] || 120;
        },
        () => core ? (core.isPlaying && !core.isCountingDown) : false,
        () => {
            const track = tracksData[Number(trackSelect.value)];
            const fileName = track ? getTrackFile(track) : "";
            return {
                singing: track?.singingIntervals?.[fileName] || [],
                excited: track?.excitementSegments?.[fileName] || [],
                chorus: track?.chorusCandidates?.[fileName] || []
            };
        }
    );

    const resourceLoad = Promise.allSettled(Object.values(resources).map(resource => resource.load()));
    await resourceLoad;
    await engine.start();

    updateStageBackground(STAGE_BACKGROUNDS[0].url);
    visualizer.start();

    inputManager.syncControlLabels();
    inputManager.updateInputModeFromDevice();
    
    const settings = inputManager.readSavedSettings();
    inputManager.applySavedSettings({
        densitySelect,
        windowSelect,
        speedInput,
        bgmVol,
        companionCountSelect,
        audienceCountSelect,
        keyTimingSelect,
        noteSpeedRef: {
            get val() { return noteSpeed; },
            set val(v) { noteSpeed = v; }
        },
        playerRef: player
    });
    
    inputManager.refreshBindingUI();
    
    // イベントリスナー登録
    inputManager.setupEventListeners((target) => {
        if (configModal.classList.contains("active") || pauseModal.classList.contains("active") || resultsModal.classList.contains("active")) return true;
        return target.closest("#settings-ui, #key-config-panel, #stage-actions, .modal-overlay");
    });

    loadTracksWhenReady();
    window.setInterval(pulseCompanionAmbience, 2400);
}

function updateStageBackground(url) {
    gameContainer.style.setProperty("--stage-bg", `url("${url}")`);
}

function pulseCompanionAmbience() {
    if (document.hidden) return;
    if (!core || !core.isPlaying || core.isPaused || core.isCountingDown || core.isApproaching || core.gameTime < 0) return;
    companionGroup.forEach((c, idx) => {
        window.setTimeout(() => {
            const COMPANION_EFFECTS = {
                dancer: { chars: "*+~", color: "#f9a8d4" },
                strings: { chars: "♫♪", color: "#7dd3fc" },
                mystic: { chars: "*<>*", color: "#5eead4" },
                salon: { chars: "+*", color: "#fde68a" },
                clap: { chars: "*", color: "#fef3c7" }
            };
            const def = COMPANION_EFFECTS[c.role] || COMPANION_EFFECTS.clap;
            visualizer.emitParticles(c.pos.x, c.pos.y - 70, def.color, "companion", def.chars[0], false);
        }, idx * 180);
    });
}

function getTrackFile(track) {
    return track && track.generated && track.generated[0] ? track.generated[0] : `${track.id}.mp3`;
}

function getTrackBase(track) {
    return getTrackFile(track).replace(/\.mp3$/i, "");
}

function populateTracks() {
    trackSelect.innerHTML = "";
    tracksData.forEach((track, idx) => {
        const fileName = getTrackFile(track);
        const opt = document.createElement("option");
        opt.value = idx;
        opt.textContent = `楽曲 ${String(idx + 1).padStart(2, "0")}`;
        opt.title = fileName;
        trackSelect.appendChild(opt);
    });
    const savedTrack = Number(inputManager.readSavedSettings().track);
    if (Number.isInteger(savedTrack) && savedTrack >= 0 && savedTrack < tracksData.length) {
        trackSelect.value = String(savedTrack);
    }
    if (!trackSelect.value && tracksData.length) {
        trackSelect.value = "0";
    }
}

function selectTrack(idx) {
    const track = tracksData[idx];
    if (!track) return;
    const fileName = getTrackFile(track);
    const baseName = getTrackBase(track);
    player.src = "../assets/audio/vocal/" + encodeURIComponent(fileName);
    player.volume = Number(bgmVol.value) / 100;
    player.load();
    const trackTitleEl = document.getElementById("track-title");
    if (trackTitleEl) trackTitleEl.textContent = "条件に合う楽曲を演奏中";
    applyTrackIcons(track);
    randomizeStageCast();
    const emoData = songEmotionsData[baseName] || { attribute: "elegant", emotion: "neutral" };
    portraitManager.loadPortraitSprite(emoData.attribute || "elegant", emoData.emotion || "neutral");
    
    if (core) {
        core.resetRunStats();
        core.updateHUD();
    }
}

function getDensityNotes(track, density) {
    const fileName = getTrackFile(track);
    const noteSet = track.notes && track.notes[fileName] && track.notes[fileName][density];
    if (Array.isArray(noteSet) && noteSet.length) {
        return noteSet;
    }
    const beatSet = track.beats && track.beats[fileName] || [];
    const stride = density === "3" ? 1 : density === "2" ? 2 : 3;
    const attrs = ["brave", "elegant", "mystic"];
    return beatSet
        .filter((_, idx) => idx % stride === 0)
        .map((time, idx) => ({ time, attribute: attrs[idx % attrs.length] }));
}

function randomizeStageCast() {
    const bg = STAGE_BACKGROUNDS[Math.floor(Math.random() * STAGE_BACKGROUNDS.length)];
    updateStageBackground(bg.url);

    const companionCount = Number(companionCountSelect.value);
    const companions = pickUnique(ELEGANT_COMPANION_POOL, companionCount);
    
    const audienceCount = Math.min(Number(audienceCountSelect.value), MAX_AUDIENCE_COUNT);
    
    // 既存アクター破棄
    audienceGroup.forEach(a => a.kill());
    companionGroup.forEach(c => c.kill());

    audienceGroup = renderAudienceEx(engine, pickStageAudience(bg, audienceCount), resources, checkLayoutIntegrityEx);
    companionGroup = updateCompanionsEx(engine, companions, resources, companionCount);
}

function checkLayoutIntegrityEx() {
    const hud = document.getElementById("layout-diagnostic-hud");
    if (!hud) return;

    let outOfBoundsSum = 0;
    let audienceOverlapSum = 0;
    let companionOverlapSum = 0;

    const coords = audienceGroup.map(a => {
        const w = a.width * a.scale.x;
        const h = a.height * a.scale.y;
        return {
            left: a.pos.x - w / 2,
            right: a.pos.x + w / 2,
            top: a.pos.y - h / 2,
            bottom: a.pos.y + h / 2
        };
    });

    const compCoords = companionGroup.map(c => {
        const w = c.width * c.scale.x;
        const h = c.height * c.scale.y;
        return {
            left: c.pos.x - w / 2,
            right: c.pos.x + w / 2,
            top: c.pos.y - h / 2, 
            bottom: c.pos.y + h / 2
        };
    });

    coords.forEach(c => {
        if (c.bottom > 462) outOfBoundsSum += (c.bottom - 462);
        if (c.left < 64) outOfBoundsSum += (64 - c.left);
        if (c.right > 1856) outOfBoundsSum += (c.right - 1856);
    });

    for (let i = 0; i < coords.length; i++) {
        for (let j = i + 1; j < coords.length; j++) {
            const c1 = coords[i];
            const c2 = coords[j];
            const overlapX = Math.max(0, Math.min(c1.right, c2.right) - Math.max(c1.left, c2.left));
            const overlapY = Math.max(0, Math.min(c1.bottom, c2.bottom) - Math.max(c1.top, c2.top));
            audienceOverlapSum += (overlapX * overlapY);
        }
    }

    coords.forEach(c => {
        compCoords.forEach(comp => {
            const overlapX = Math.max(0, Math.min(c.right, comp.right) - Math.max(c.left, comp.left));
            const overlapY = Math.max(0, Math.min(c.bottom, comp.bottom) - Math.max(c.top, comp.top));
            companionOverlapSum += (overlapX * overlapY);
        });
    });

    document.getElementById("diag-out-of-bounds").textContent = `Out of Stage: ${Math.round(outOfBoundsSum)}px`;
    document.getElementById("diag-audience-overlap").textContent = `Audience Overlap: ${Math.round(audienceOverlapSum)}px`;
    document.getElementById("diag-companion-overlap").textContent = `Companion Overlap: ${Math.round(companionOverlapSum)}px`;

    const hasError = outOfBoundsSum > 0 || companionOverlapSum > 0;
    hud.style.borderColor = hasError ? "#ef4444" : "#10b981";
    hud.style.boxShadow = hasError ? "0 0 12px rgba(239, 68, 68, 0.4)" : "0 0 12px rgba(16, 185, 129, 0.4)";
}

function loadTracksWhenReady() {
    const loadedTracks = window.tracks || (typeof tracks !== "undefined" ? tracks : []);
    const loadedSongEmotions = window.songEmotions || (typeof songEmotions !== "undefined" ? songEmotions : {});
    if (Array.isArray(loadedTracks) && loadedTracks.length) {
        tracksData = loadedTracks;
        songEmotionsData = loadedSongEmotions;
        populateTracks();
        selectTrack(getSelectedTrackIndex());
    } else {
        setTimeout(loadTracksWhenReady, 100);
    }
}

function getSelectedTrackIndex() {
    const raw = Number(trackSelect.value);
    if (Number.isInteger(raw) && raw >= 0 && raw < tracksData.length) return raw;
    if (trackSelect.selectedIndex >= 0 && trackSelect.selectedIndex < tracksData.length) return trackSelect.selectedIndex;
    return tracksData.length ? 0 : -1;
}

function applyTrackIcons(track) {
    const rawId = String(track && track.id || "");
    const parts = rawId.split("_");
    let insCode = 201;
    let typeCode = 211;
    let themeCode = 221;
    let isSpecial = false;
    let specialRegion = 1;
    let specialAttr = "elegant";

    if (parts.length >= 4) {
        if (parts[1] === "special") {
            isSpecial = true;
            specialRegion = parseInt(parts[2], 10) || 1;
            specialAttr = parts[3] || "elegant";
        } else {
            insCode = parseInt(parts[1], 10) || insCode;
            typeCode = parseInt(parts[2], 10) || typeCode;
            themeCode = parseInt(parts[3], 10) || themeCode;
        }
    }

    const iconDefs = {
        instrument: { sheet: "icon_sheet_03_music_bonus_code.webp", index: 18, title: "楽器" },
        type: { sheet: "icon_sheet_03_music_bonus_code.webp", index: 30, title: "曲種" },
        theme: { sheet: "icon_sheet_03_music_bonus_code.webp", index: 43, title: "テーマ" }
    };

    if (isSpecial) {
        iconDefs.instrument.index = 4;
        iconDefs.type.sheet = "icon_sheet_02_card_event_code.webp";
        iconDefs.type.index = 16 + (specialRegion - 1);
        iconDefs.theme.sheet = "icon_sheet_01_minigame_ui.webp";
        iconDefs.theme.index = specialAttr === "mystic" ? 26 : specialAttr === "brave" ? 24 : 25;
    } else {
        const instrumentMap = { 101: 16, 102: 17, 201: 18, 202: 19, 301: 20, 302: 21, 401: 22, 402: 23, 501: 24, 502: 25, 601: 26, 602: 27 };
        const typeMap = { 111: 28, 112: 29, 211: 30, 212: 31, 311: 32, 312: 33, 411: 34, 412: 35, 511: 36, 512: 37, 611: 38, 612: 39 };
        const themeMap = {
            121: 40, 122: 41, 123: 42,
            221: 43, 222: 44, 223: 45,
            321: 46, 322: 47, 323: 48,
            421: 49, 422: 50, 423: 51,
            521: 52, 522: 53, 523: 54,
            621: 55, 622: 56, 623: 57
        };
        iconDefs.instrument.index = instrumentMap[insCode] ?? iconDefs.instrument.index;
        iconDefs.type.index = typeMap[typeCode] ?? iconDefs.type.index;
        iconDefs.theme.index = themeMap[themeCode] ?? iconDefs.theme.index;
    }

    function iconPosition(index) {
        const tile = 42;
        const col = index % 8;
        const row = Math.floor(index / 8);
        return `${-(col * tile)}px ${-(row * tile)}px`;
    }

    for (const [key, def] of Object.entries(iconDefs)) {
        const el = conditionIconEls[key];
        if (!el) continue;
        el.style.backgroundImage = `url("../assets/images/icon/${def.sheet}")`;
        el.style.backgroundPosition = iconPosition(def.index);
        el.title = def.title;
    }
}

